FUNCTION ComputeViewMatrix(eye, lookAt, up)
 // Compute forward vector (normalized look direction)
 forward = normalize(lookAt - eye)

 // Compute right vector (perpendicular to forward and up)
 right = normalize(cross(forward, up))

 // Compute corrected up vector
 newUp = cross(right, forward)

 // Build 4x4 view matrix (column-major)
 viewMatrix = [
 right.x, newUp.x, -forward.x, 0,
 right.y, newUp.y, -forward.y, 0,
 right.z, newUp.z, -forward.z, 0,
 -dot(right, eye), -dot(newUp, eye), dot(forward, eye), 1
 ]

 RETURN viewMatrix
END FUNCTION
